// Extract topic_slug, date_key, and publish_job_id from the orchestrator input.
const input = $input.first().json;
const topic_slug = input.topic_slug;
const date_key = input.date_key;
const publish_job_id = input.publish_job_id;

if (!topic_slug || !date_key || !publish_job_id) {
  throw new Error(`Missing required inputs. Got: topic_slug=${topic_slug}, date_key=${date_key}, publish_job_id=${publish_job_id}`);
}

return [{ json: { topic_slug, date_key, publish_job_id } }];

