// Merge alerts and clusters into the aggregate context.
const ctx = $('Validate Input').first().json;
const alertsResp = $('Fetch Alerts from D1').first().json;
const clustersResp = $('Fetch Clusters from D1').first().json;

const alerts = alertsResp?.result?.[0]?.results || [];
const clusters = clustersResp?.result?.[0]?.results || [];

if (alerts.length === 0) {
  throw new Error(`No active alerts found for ${ctx.topic_slug} on ${ctx.date_key}. Cannot generate daily summary.`);
}

return [{
  json: {
    topic_slug: ctx.topic_slug,
    date_key: ctx.date_key,
    publish_job_id: ctx.publish_job_id,
    alerts,
    clusters,
    alert_count: alerts.length,
    cluster_count: clusters.length
  }
}];
